import { makeStyles } from '@material-ui/core/styles';

export default makeStyles((theme) => ({
  container: {
    textAlign: 'center',
  },
  posts: {
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
  },
  name: {
      color: '#F0F4EF',
  },
}));
